float exp(float y) {
    float d;
    *((short*)&d + 0) = 0;
    *((short*)&d + 1) = (short)(184 * y + (16256 - 7));
    return d;
}

float sum_of_products(float kernel[16],float a[16]) {
    float result = 0.0f;
    for (int i = 0; i < 16; i++) {
        result += kernel[i] * a[i];
    }
    return result;
}

